"""PY-SSL-001 — Insecure SSL context (certificate verification disabled).

Flags a bare ``ssl.SSLContext()`` (or ``ssl._create_unverified_context()``),
which defaults to ``verify_mode=CERT_NONE`` and ``check_hostname=False``. The
secure factory ``ssl.create_default_context()`` is never flagged. When the
context is bound to a variable and later hardened in the same function, the
finding is suppressed; inline use (e.g. ``ssl=ssl.SSLContext() if ... else None``)
cannot be hardened and is reported with high confidence.
"""

from __future__ import annotations

import ast
from collections.abc import Iterator

from scanner.context import FileContext
from scanner.models import Confidence, Finding
from scanner.rules import register
from scanner.rules.base import Rule

_INSECURE_CTORS = {("ssl", "SSLContext"), ("ssl", "_create_unverified_context")}
_INSECURE_CTOR_NAMES = {"SSLContext", "_create_unverified_context"}
_INSECURE_VERIFY_MODES = {"CERT_NONE"}


@register
class InsecureSSLContextRule(Rule):
    id = "PY-SSL-001"
    name = "Insecure SSL context (certificate verification disabled)"
    cvss_vector = "CVSS:3.1/AV:N/AC:L/PR:N/UI:N/S:U/C:H/I:N/A:N"
    confidence = Confidence.PROBABLE
    cwe = "CWE-295"
    remediation = (
        "Use ssl.create_default_context(), which verifies certificates and "
        "hostnames. If you must construct an SSLContext manually, set "
        "check_hostname=True and verify_mode=ssl.CERT_REQUIRED before use."
    )
    references = (
        "https://docs.python.org/3/library/ssl.html#ssl.create_default_context",
        "https://cwe.mitre.org/data/definitions/295.html",
    )

    def analyze(self, ctx: FileContext) -> Iterator[Finding]:
        for node in ast.walk(ctx.tree):
            if not (isinstance(node, ast.Call) and self._is_insecure_ctor(node.func)):
                continue
            if self._hardened_in_scope(node, ctx):
                continue
            inline = self._assignment_target(node) is None
            yield self.finding(
                ctx,
                node,
                message=(
                    "`ssl.SSLContext()` defaults to verify_mode=CERT_NONE and "
                    "check_hostname=False, disabling TLS certificate verification "
                    "(man-in-the-middle risk). Use ssl.create_default_context()."
                ),
                confidence=Confidence.CONFIRMED if inline else Confidence.PROBABLE,
            )

    @staticmethod
    def _is_insecure_ctor(func: ast.AST) -> bool:
        if isinstance(func, ast.Attribute) and isinstance(func.value, ast.Name):
            return (func.value.id, func.attr) in _INSECURE_CTORS
        if isinstance(func, ast.Name):
            return func.id in _INSECURE_CTOR_NAMES
        return False

    @staticmethod
    def _assignment_target(call: ast.Call):
        parent = getattr(call, "parent", None)
        if (
            isinstance(parent, ast.Assign)
            and len(parent.targets) == 1
            and isinstance(parent.targets[0], ast.Name)
        ):
            return parent.targets[0].id
        if isinstance(parent, ast.AnnAssign) and isinstance(parent.target, ast.Name):
            return parent.target.id
        return None

    @staticmethod
    def _enclosing_scope(node: ast.AST):
        cur = getattr(node, "parent", None)
        while cur is not None:
            if isinstance(cur, (ast.FunctionDef, ast.AsyncFunctionDef, ast.Module)):
                return cur
            cur = getattr(cur, "parent", None)
        return None

    def _hardened_in_scope(self, call: ast.Call, ctx: FileContext) -> bool:
        target = self._assignment_target(call)
        if target is None:
            return False  # inline use cannot be hardened
        scope = self._enclosing_scope(call)
        if scope is None:
            return False
        for stmt in ast.walk(scope):
            if isinstance(stmt, ast.Assign):
                for tgt in stmt.targets:
                    if (
                        isinstance(tgt, ast.Attribute)
                        and isinstance(tgt.value, ast.Name)
                        and tgt.value.id == target
                    ):
                        if tgt.attr == "check_hostname":
                            return True
                        if tgt.attr == "verify_mode" and not self._is_cert_none(stmt.value):
                            return True
            if (
                isinstance(stmt, ast.Call)
                and isinstance(stmt.func, ast.Attribute)
                and isinstance(stmt.func.value, ast.Name)
                and stmt.func.value.id == target
                and stmt.func.attr in {"load_verify_locations", "load_default_certs"}
            ):
                return True
        return False

    @staticmethod
    def _is_cert_none(value: ast.AST) -> bool:
        if isinstance(value, ast.Attribute):
            return value.attr in _INSECURE_VERIFY_MODES
        if isinstance(value, ast.Name):
            return value.id in _INSECURE_VERIFY_MODES
        return False

"""Rule registry with auto-discovery.

Adding a rule is: drop a module in ``scanner/rules/``, subclass ``Rule``, and
decorate the class with ``@register``. ``all_rules()`` imports every module in
this package and instantiates the selected rules.
"""

from __future__ import annotations

import importlib
import pkgutil

_REGISTRY: dict = {}


def register(cls):
    if not getattr(cls, "id", ""):
        raise ValueError(f"rule {cls!r} must define a non-empty id")
    if cls.id in _REGISTRY:
        raise ValueError(f"duplicate rule id: {cls.id}")
    _REGISTRY[cls.id] = cls
    return cls


def _discover() -> None:
    import scanner.rules as pkg

    for mod in pkgutil.iter_modules(pkg.__path__):
        if mod.name not in ("base", "__init__"):
            importlib.import_module(f"scanner.rules.{mod.name}")


def all_rules(select=None, skip=None) -> list:
    _discover()
    ids = set(_REGISTRY)
    if select:
        ids &= set(select)
    if skip:
        ids -= set(skip)
    return [_REGISTRY[rule_id]() for rule_id in sorted(ids)]


def registry_ids() -> list:
    _discover()
    return sorted(_REGISTRY)

