"""PY-LOG-001 — Credential-bearing value written to a logging/breadcrumb sink.

CWE-532: Insertion of Sensitive Information into Log File. Flags a call to a
logging sink (``logger.info/debug/warning/error/exception/critical``, ``.log``,
or ``add_breadcrumb``) whose message arguments include a value referenced by a
credential-shaped name (``token``, ``secret``, ``password``, ``api_key``,
``push_url`` with embedded creds, ...).

To stay precise the rule reports only a *direct* reference — a bare ``Name`` /
``Attribute`` or one interpolated in an f-string / ``%`` / ``+`` expression.
A value passed through a wrapping call (``redact(token)``, ``mask(push_url)``)
is assumed sanitized and is not flagged.
"""

from __future__ import annotations

import ast
import re
from collections.abc import Iterator

from scanner.context import FileContext
from scanner.models import Confidence, Finding
from scanner.rules import register
from scanner.rules.base import Rule

_SINK_ATTRS = {
    "log", "debug", "info", "warning", "warn",
    "error", "exception", "critical", "add_breadcrumb",
}
_SINK_NAMES = {"add_breadcrumb"}

# Substrings that mark an identifier as credential-bearing.
_CRED_RE = re.compile(
    r"(password|passwd|secret|token|api_?key|access_key|private_key|"
    r"credential|push_url|auth_url)",
    re.IGNORECASE,
)


@register
class SensitiveLogRule(Rule):
    id = "PY-LOG-001"
    name = "Sensitive value written to log/breadcrumb sink"
    cvss_vector = "CVSS:3.1/AV:L/AC:L/PR:H/UI:N/S:U/C:L/I:N/A:N"
    confidence = Confidence.PROBABLE
    cwe = "CWE-532"
    remediation = (
        "Do not log credentials, tokens, or credentialed URLs. Redact or mask "
        "the value before logging (e.g. log a fingerprint, not the secret), or "
        "strip credentials from URLs prior to emitting them."
    )
    references = (
        "https://cwe.mitre.org/data/definitions/532.html",
        "https://owasp.org/Top10/A09_2021-Security_Logging_and_Monitoring_Failures/",
    )

    def analyze(self, ctx: FileContext) -> Iterator[Finding]:
        for node in ast.walk(ctx.tree):
            if not isinstance(node, ast.Call) or not self._is_sink(node.func):
                continue
            if any(self._credential_ref(arg) for arg in node.args):
                yield self.finding(
                    ctx,
                    node,
                    message=(
                        "Credential-shaped value is passed directly to a logging "
                        "sink, which can persist secrets in logs or error-tracking "
                        "breadcrumbs (CWE-532). Redact before logging."
                    ),
                )

    @staticmethod
    def _is_sink(func: ast.AST) -> bool:
        if isinstance(func, ast.Attribute):
            return func.attr in _SINK_ATTRS
        if isinstance(func, ast.Name):
            return func.id in _SINK_NAMES
        return False

    @classmethod
    def _credential_ref(cls, node: ast.AST) -> bool:
        """True if ``node`` directly references a credential-named value.

        Recurses through string-building containers (f-string, ``%``/``+``,
        tuple/list) but stops at a ``Call`` — a wrapped value is assumed
        sanitized.
        """
        if isinstance(node, ast.Name):
            return bool(_CRED_RE.search(node.id))
        if isinstance(node, ast.Attribute):
            return bool(_CRED_RE.search(node.attr))
        if isinstance(node, ast.JoinedStr):
            return any(
                isinstance(v, ast.FormattedValue) and cls._credential_ref(v.value)
                for v in node.values
            )
        if isinstance(node, ast.BinOp) and isinstance(node.op, (ast.Add, ast.Mod)):
            return cls._credential_ref(node.left) or cls._credential_ref(node.right)
        if isinstance(node, (ast.Tuple, ast.List)):
            return any(cls._credential_ref(e) for e in node.elts)
        return False

