import logging

logger = logging.getLogger(__name__)


def log_token(api_token):
    logger.info("token is %s", api_token)  # FLAG: PY-LOG-001


def log_push_url(remote_name, push_url):
    logger.debug(f"Configuring remote '{remote_name}': {push_url}")  # FLAG: PY-LOG-001


def breadcrumb(add_breadcrumb, password):
    add_breadcrumb("auth header: " + password)  # FLAG: PY-LOG-001

